5. **输出要求**：
                           - 仅返回标准C代码
                           - 禁止包含解释性文字
                           - 仅修正该函数本身，不要修改函数名，把该函数中调用的其他函数(依赖函数中已给出)全部当做已声明(调用的函数的传入参数与依赖函数中的定义保持一致),
                           不要重复声明，不要添加其他任何函数!!
                           - 代码中用到的全局变量全部已定义，不要重复定义！！
                           - 依赖的函数已给出，调用依赖函数时要根据给出的代码调用，传参与依赖函数的定义保持一致！
                        /* 示例转换 */

                        // 原始代码：
    '''
                        int __fastcall displayAllBooks(__int64 a1) {{
                              int result; // eax
                              int i; // [rsp+1Ch] [rbp-4h]

                              if ( !*(_DWORD *)(a1 + 20800) )
                                return puts(aA_8);
                              for ( i = 0; ; ++i )
                              {{
                                result = *(_DWORD *)(a1 + 20800);
                                if ( i >= result )
                                  break;
                                printf(aA_4, *(unsigned int *)(a1 + 208LL * i + 200));
                                printf(aA_5, a1 + 208LL * i);
                                printf(aA_6, 208LL * i + 96 + a1 + 4);
                                printf(aA_7, *(float *)(a1 + 208LL * i + 204));
                                puts("------------------------");
                              }}
                              return result;
                            }}


                        // 转换后：
                        void displayAllBooks(Library *lib) {{
                    if (lib->count == 0) {{
                        printf("图书馆暂无图书。\n");
                        return;
                    }}
                    for (int i = 0; i < lib->count; i++) {{
                        printf("图书 ID: %d\n", lib->books[i].id);
                        printf("图书标题: %s\n", lib->books[i].title);
                        printf("图书作者: %s\n", lib->books[i].author);
                        printf("图书价格: %.2f\n", lib->books[i].price);
                        printf("------------------------\n");
                    }}
                }}
